const item = $input.first();
const base64 = item.json.content_base64;
const mimeType = item.json.mime_type;
const buffer = Buffer.from(base64, 'base64');
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

let text = '';
let totalPages = 0;
let skippedPages = 0;
let ocrPages = 0;

const https = require('https');
const ycApiKey = $env.YC_API_KEY;

async function runOcrYandex(imageBase64, imgMime) {
  return new Promise((resolve) => {
    const body = JSON.stringify({ mimeType: imgMime || 'image/png', languageCodes: ['ru', 'en'], content: imageBase64 });
    const req = https.request('https://ocr.api.cloud.yandex.net/ocr/v1/recognizeText', {
      method: 'POST',
      headers: { 'Authorization': 'Api-Key ' + ycApiKey, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
    }, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          resolve(parsed.result?.textAnnotation?.fullText || '');
        } catch(e) { resolve(''); }
      });
    });
    req.on('error', () => resolve(''));
    req.write(body);
    req.end();
  });
}

function runOcrLocal(imagePath) {
  try {
    return execSync(
      'tesseract "' + imagePath + '" stdout -l rus+eng --oem 1 --psm 3',
      { maxBuffer: 50 * 1024 * 1024 }
    ).toString().trim();
  } catch (e) {
    return '';
  }
}

async function runOcr(imagePathOrBase64, imgMime) {
  let b64 = imagePathOrBase64;
  let filePath = null;
  if (!imgMime) {
    filePath = imagePathOrBase64;
    b64 = fs.readFileSync(imagePathOrBase64).toString('base64');
    imgMime = 'image/png';
  }
  if (ycApiKey) {
    const result = await runOcrYandex(b64, imgMime);
    if (result.length > 0) return result;
  }
  if (filePath && fs.existsSync(filePath)) {
    return runOcrLocal(filePath);
  }
  const tmpFile = path.join(os.tmpdir(), 'ocr_' + Date.now() + '.png');
  try {
    fs.writeFileSync(tmpFile, Buffer.from(b64, 'base64'));
    return runOcrLocal(tmpFile);
  } catch(e) {
    return '';
  } finally {
    try { fs.unlinkSync(tmpFile); } catch(e) {}
  }
}

const IMAGE_MIMES = ['image/png', 'image/jpeg', 'image/tiff', 'image/bmp', 'image/webp'];
const OFFICE_MIMES = [
  'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  'application/vnd.oasis.opendocument.text'
];

if (mimeType === 'application/pdf') {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rag-'));
  try {
    const pdfPath = path.join(tmpDir, 'input.pdf');
    fs.writeFileSync(pdfPath, buffer);
    try {
      const pagesOut = execSync('pdfinfo "' + pdfPath + '" 2>/dev/null | grep Pages | awk "{print \\$2}"', { maxBuffer: 10 * 1024 * 1024 }).toString().trim();
      totalPages = parseInt(pagesOut, 10) || 1;
    } catch(e) { totalPages = 1; }
    let pdfText = '';
    try {
      pdfText = execSync('pdftotext -layout "' + pdfPath + '" -', { maxBuffer: 50 * 1024 * 1024 }).toString();
    } catch(e) { pdfText = ''; }
    if (pdfText.trim().length >= 10) {
      text = pdfText;
    } else {
      for (let p = 1; p <= totalPages; p++) {
        try {
          execSync('pdftoppm -png -r 300 -f ' + p + ' -l ' + p + ' "' + pdfPath + '" "' + tmpDir + '/page"', { maxBuffer: 50 * 1024 * 1024 });
          const files = fs.readdirSync(tmpDir).filter(f => f.startsWith('page-') && f.endsWith('.png'));
          if (files.length > 0) {
            const imgPath = path.join(tmpDir, files[files.length - 1]);
            const imgB64 = fs.readFileSync(imgPath).toString('base64');
            const ocrText = await runOcr(imgB64, 'image/png');
            if (ocrText.length > 10) {
              text += (text ? '\n\n' : '') + ocrText;
              ocrPages++;
            } else {
              skippedPages++;
            }
            try { fs.unlinkSync(imgPath); } catch(e) {}
          } else {
            skippedPages++;
          }
        } catch (e) {
          skippedPages++;
        }
      }
    }
  } catch (e) {
    text = '';
    if (totalPages === 0) totalPages = 1;
    skippedPages = totalPages;
  } finally {
    try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch(e) {}
  }
} else if (IMAGE_MIMES.includes(mimeType)) {
  totalPages = 1;
  try {
    text = await runOcr(base64, mimeType);
    if (text.length > 0) {
      ocrPages = 1;
    } else {
      skippedPages = 1;
    }
  } catch (e) {
    text = '';
    skippedPages = 1;
  }
} else if (mimeType === 'application/rtf') {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rag-'));
  try {
    const filePath = path.join(tmpDir, 'input.rtf');
    fs.writeFileSync(filePath, buffer);
    const raw = execSync('unrtf --text "' + filePath + '"', { maxBuffer: 50 * 1024 * 1024 }).toString();
    text = raw.split('\n').filter(l => !l.startsWith('###') && l.trim() !== '-----------------').join('\n').trim();
  } catch (e) {
    text = '';
    skippedPages = 1;
    totalPages = 1;
  } finally {
    try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch(e) {}
  }
} else if (mimeType === 'application/msword') {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rag-'));
  try {
    const filePath = path.join(tmpDir, 'input.doc');
    fs.writeFileSync(filePath, buffer);
    text = execSync('antiword "' + filePath + '"', { maxBuffer: 50 * 1024 * 1024 }).toString().trim();
  } catch (e) {
    text = '';
    skippedPages = 1;
    totalPages = 1;
  } finally {
    try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch(e) {}
  }
} else if (OFFICE_MIMES.includes(mimeType)) {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rag-'));
  try {
    const { parseOffice } = require('officeparser');
    const extMap = {
      'application/vnd.openxmlformats-officedocument.presentationml.presentation': '.pptx',
      'application/vnd.oasis.opendocument.text': '.odt'
    };
    const ext = extMap[mimeType];
    const filePath = path.join(tmpDir, 'input' + ext);
    fs.writeFileSync(filePath, buffer);
    const result = await parseOffice(filePath);
    if (typeof result === 'string') {
      text = result;
    } else if (result && result.content) {
      text = result.content.map(p => p.text || '').join('\n');
    }
  } catch (e) {
    text = '';
    skippedPages = 1;
    totalPages = 1;
  } finally {
    try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch(e) {}
  }
} else if (mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document') {
  try {
    const mammoth = require('mammoth');
    const result = await mammoth.extractRawText({ buffer });
    text = result.value || '';
  } catch (e) {
    text = '';
    skippedPages = 1;
    totalPages = 1;
  }
} else if (mimeType === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet') {
  try {
    const XLSX = require('xlsx');
    const workbook = XLSX.read(buffer, { type: 'buffer' });
    text = workbook.SheetNames.map(name => {
      const sheet = workbook.Sheets[name];
      return XLSX.utils.sheet_to_csv(sheet);
    }).join('\n\n');
  } catch (e) {
    text = '';
    skippedPages = 1;
    totalPages = 1;
  }
} else {
  text = buffer.toString('utf-8');
}

return [{ json: { org_id: item.json.org_id, document_id: item.json.document_id, filename: item.json.filename, extracted_text: text, total_pages: totalPages, skipped_pages: skippedPages, ocr_pages: ocrPages } }];

const item = $input.first();
const text = item.json.extracted_text;
const chunkSize = 2000;
const overlap = 200;

const chunks = [];
let start = 0;
while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  chunks.push({ content: text.slice(start, end), chunk_index: chunks.length });
  start += chunkSize - overlap;
  if (end >= text.length) break;
}

return [{ json: { org_id: item.json.org_id, document_id: item.json.document_id, filename: item.json.filename, chunks, chunk_count: chunks.length, skipped_pages: item.json.skipped_pages || 0, total_pages: item.json.total_pages || 0, ocr_pages: item.json.ocr_pages || 0 } }];

const crypto = require('crypto');
const https = require('https');

const chunksData = $('Split into Chunks').first().json;
const { org_id, document_id, filename, chunks, chunk_count } = chunksData;
const apiKey = $env.YC_API_KEY;
const modelUri = 'emb://b1glrh7ge8kcm9870erg/text-search-doc/latest';

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function embed(text) {
  for (let attempt = 0; attempt < 3; attempt++) {
    const result = await new Promise((resolve, reject) => {
      const body = JSON.stringify({ modelUri, text });
      const req = https.request('https://llm.api.cloud.yandex.net/foundationModels/v1/textEmbedding', {
        method: 'POST',
        headers: { 'Authorization': 'Api-Key ' + apiKey, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
      }, (res) => {
        let data = '';
        res.on('data', d => data += d);
        res.on('end', () => {
          if (res.statusCode === 429 || res.statusCode >= 500) {
            resolve({ _retry: true, status: res.statusCode, data });
          } else if (res.statusCode !== 200) {
            reject(new Error('Yandex Embed ' + res.statusCode + ': ' + data));
          } else {
            resolve(JSON.parse(data));
          }
        });
      });
      req.on('error', reject);
      req.write(body);
      req.end();
    });
    if (result._retry) {
      if (attempt < 2) { await sleep(1000 * Math.pow(2, attempt)); continue; }
      throw new Error('Yandex Embed ' + result.status + ' after 3 retries: ' + result.data);
    }
    return result;
  }
}

const points = [];
const chunkRecords = [];

for (let i = 0; i < chunks.length; i++) {
  if (i > 0) await sleep(200);
  const result = await embed(chunks[i].content);
  const qdrantId = crypto.randomUUID();
  points.push({
    id: qdrantId,
    vector: result.embedding,
    payload: { content: chunks[i].content, document_id, chunk_index: chunks[i].chunk_index, filename }
  });
  chunkRecords.push({
    document_id,
    content: chunks[i].content,
    chunk_index: chunks[i].chunk_index,
    qdrant_id: qdrantId
  });
}

return [{ json: { org_id, document_id, filename, chunk_count, points, chunkRecords, skipped_pages: chunksData.skipped_pages || 0, total_pages: chunksData.total_pages || 0, ocr_pages: chunksData.ocr_pages || 0 } }];

const { Client } = require('pg');
const d = $('Yandex: Embed & Build Points').first().json;
const { chunkRecords, chunk_count, document_id, skipped_pages } = d;

const client = new Client({
  host: $env.APP_PG_HOST,
  port: parseInt($env.APP_PG_PORT),
  user: $env.APP_PG_USER,
  password: $env.APP_PG_PASSWORD,
  database: $env.APP_PG_DATABASE,
});

await client.connect();
try {
  await client.query('BEGIN');
  for (const c of chunkRecords) {
    await client.query(
      'INSERT INTO "DocumentChunk" (document_id, content, chunk_index, qdrant_id) VALUES ($1, $2, $3, $4)',
      [c.document_id, c.content, c.chunk_index, c.qdrant_id]
    );
  }
  let status = 'error';
  if (chunk_count > 0 && (skipped_pages || 0) > 0) status = 'partial';
  else if (chunk_count > 0) status = 'ready';
  await client.query(
    'UPDATE "Document" SET status = $1, chunk_count = $2, updated_at = NOW() WHERE id = $3',
    [status, chunk_count, document_id]
  );
  await client.query('COMMIT');
} catch (e) {
  await client.query('ROLLBACK');
  throw e;
} finally {
  await client.end();
}

return [{ json: d }];

const { Client } = require('pg');
const d = $input.first().json;

const client = new Client({
  host: $env.APP_PG_HOST,
  port: parseInt($env.APP_PG_PORT),
  user: $env.APP_PG_USER,
  password: $env.APP_PG_PASSWORD,
  database: $env.APP_PG_DATABASE,
});

await client.connect();
try {
  await client.query(
    'UPDATE "Document" SET status = $1, chunk_count = 0, updated_at = NOW() WHERE id = $2',
    ['error', d.document_id]
  );
} finally {
  await client.end();
}

return [{ json: { org_id: d.org_id, document_id: d.document_id, filename: d.filename, chunk_count: 0, skipped_pages: d.skipped_pages || 0, total_pages: d.total_pages || 0, ocr_pages: d.ocr_pages || 0 } }];

const { Client } = require('pg');

let document_id;
try {
  document_id = $('Split into Chunks').first().json.document_id;
} catch(e) {
  try { document_id = $('Merge PG + Input').first().json.document_id; } catch(e2) { document_id = null; }
}

if (document_id) {
  const client = new Client({
    host: $env.APP_PG_HOST,
    port: parseInt($env.APP_PG_PORT),
    user: $env.APP_PG_USER,
    password: $env.APP_PG_PASSWORD,
    database: $env.APP_PG_DATABASE,
  });
  await client.connect();
  try {
    await client.query(
      'UPDATE "Document" SET status = $1, updated_at = NOW() WHERE id = $2',
      ['error', document_id]
    );
  } finally {
    await client.end();
  }
}

const errItem = $input.first();
const errorMsg = errItem.json?.message || errItem.json?.error?.message || 'Indexing failed';
return [{ json: { success: false, document_id, error: errorMsg } }];
